func hostOnly(addr string) string {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		return addr
	}
	return host
}

type ClientHello struct {
	Name string `json:"name"`
}

type Envelope struct {
	Type string          `json:"type"`
	Data json.RawMessage `json:"data"`
}

type ChatMessage struct {
	Text string `json:"text"`
}

func main() {
	addr := getenv("ADDR", ":7777")
	s := NewServer()
	cmds := buildCommands()

	ln, err := net.Listen("tcp", addr)
	if err != nil {
		log.Fatalf("listen: %v", err)
	}
	s.logger.Printf("listening on %s", addr)

	for {
		conn, err := ln.Accept()
		if err != nil {
			s.logger.Printf("accept: %v", err)
			continue
		}
		go handleConn(s, cmds, conn)
	}
}

func handleConn(s *Server, cmds *CommandRegistry, conn net.Conn) {
	defer func() { _ = conn.Close() }()

	remote := conn.RemoteAddr().String()
	ip := hostOnly(remote)
	if banned, _ := s.isBannedIP(ip); banned {
		s.cleanupBan(ip)
		if banned2, exp := s.isBannedIP(ip); banned2 {
			msg := "banned"
			if !exp.IsZero() {
				msg = "banned until " + exp.Format(time.RFC3339)
			} else {
				msg = "banned permanently"
			}
			_, _ = conn.Write([]byte(`{"type":"system","text":"Connection refused: ` + msg + `"}` + "\n"))
			return
		}
	}

	_ = conn.SetReadDeadline(time.Now().Add(15 * time.Second))
	br := bufio.NewReaderSize(conn, 64*1024)

	role := RolePlayer
	name := ""

	line, err := br.ReadString('\n')
	if err != nil {
		return
	}
	line = strings.TrimSpace(line)

	headers := parseHeadersLine(line)
	role = parseRole(headers["role"])
	if n, ok := headers["name"]; ok {
		name = strings.TrimSpace(n)
	}

	if name == "" {
		helloLine, err := br.ReadString('\n')
		if err != nil {
			return
		}
		helloLine = strings.TrimSpace(helloLine)
		var env Envelope
		if json.Unmarshal([]byte(helloLine), &env) == nil && env.Type == "hello" {
			var h ClientHello
			if json.Unmarshal(env.Data, &h) == nil {
				name = strings.TrimSpace(h.Name)
			}
		} else {
			var h2 ClientHello
			if json.Unmarshal([]byte(helloLine), &h2) == nil {
				name = strings.TrimSpace(h2.Name)
			}
		}
	}

	if name == "" {
		name = "Player-" + randomID()[:6]
	}
	if len(name) > 24 {
		name = name[:24]
	}

	_ = conn.SetReadDeadline(time.Time{})

	c := &Client{
		ID:       randomID(),
		Name:     name,
		Role:     role,
		Conn:     conn,
		Addr:     remote,
		LastSeen: time.Now(),
	}
	s.addClient(c)
	defer func() {
		s.removeClient(c.ID)
		s.Broadcast(map[string]any{"type": "system", "text": fmt.Sprintf("%s left", c.Name)})
	}()

	c.Send(map[string]any{
		"type": "welcome",
		"data": map[string]any{
			"id":   c.ID,
			"name": c.Name,
			"role": c.Role.String(),
		},
	})
	s.Broadcast(map[string]any{"type": "system", "text": fmt.Sprintf("%s joined (role=%s)", c.Name, c.Role.String())})

	for {
		ln, err := br.ReadString('\n')
		if err != nil {
			return
		}
		ln = strings.TrimSpace(ln)
		if ln == "" {
			continue
		}
		c.LastSeen = time.Now()

		var env Envelope
		if json.Unmarshal([]byte(ln), &env) == nil && env.Type != "" {
			switch env.Type {
			case "chat":
				var m ChatMessage
				if err := json.Unmarshal(env.Data, &m); err != nil {
					c.Send(map[string]any{"type": "error", "text": "invalid chat payload"})
					continue
				}
				handleChatLine(s, cmds, c, m.Text)
			case "ping":
				c.Send(map[string]any{"type": "pong", "ts": time.Now().Unix()})
			default:
				c.Send(map[string]any{"type": "error", "text": "unknown message type"})
			}
			continue
		}

		var m2 ChatMessage
		if json.Unmarshal([]byte(ln), &m2) == nil && m2.Text != "" {
			handleChatLine(s, cmds, c, m2.Text)
			continue
		}

		handleChatLine(s, cmds, c, ln)
	}
}

func handleChatLine(s *Server, cmds *CommandRegistry, actor *Client, text string) {
	text = strings.TrimSpace(text)
	if text == "" {
		return
	}
	if strings.HasPrefix(text, "/") {
		m := reCmd.FindStringSubmatch(text)
		if m == nil {
			actor.Send(map[string]any{"type": "error", "text": "invalid command format"})
			return
		}
		cmdName := strings.ToLower(m[1])
		argStr := ""
		if len(m) > 2 {
			argStr = m[2]
		}
		args := parseArgs(argStr)

		cmd, ok := cmds.Get(cmdName)
		if !ok {
			actor.Send(map[string]any{"type": "error", "text": "unknown command: " + cmdName})
			return
		}
		if actor.Role < cmd.MinRole {
			actor.Send(map[string]any{"type": "error", "text": fmt.Sprintf("forbidden: requires %s", cmd.MinRole.String())})
			return
		}
		if err := cmd.Handler(s, actor, args); err != nil {
			actor.Send(map[string]any{"type": "error", "text": err.Error()})
		}
		return
	}
	s.BroadcastChat(actor, text)
}

func parseHeadersLine(line string) map[string]string {
	out := map[string]string{}
	line = strings.TrimSpace(line)
	if line == "" {
		return out
	}
	if strings.HasPrefix(line, "{") {
		var m map[string]any
		if json.Unmarshal([]byte(line), &m) == nil {
			for k, v := range m {
				out[strings.ToLower(k)] = fmt.Sprint(v)
			}
		}
		return out
	}
	parts := strings.Split(line, ";")
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p == "" {
			continue
		}
		kv := strings.SplitN(p, ":", 2)
		if len(kv) != 2 {
			kv = strings.SplitN(p, "=", 2)
			if len(kv) != 2 {
				continue
			}
		}
		k := strings.ToLower(strings.TrimSpace(kv[0]))
		v := strings.TrimSpace(kv[1])
		out[k] = v
	}
	return out
}

func getenv(k, def string) string {
	v := os.Getenv(k)
	if strings.TrimSpace(v) == "" {
		return def
	}
	return v
}